import { useEffect, useState } from "react";
import API_URL from "../api"; // Import the API base URL

function Home() {
  const [capsules, setCapsules] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchCapsules = async () => {
      try {
        const token = localStorage.getItem("token"); // Get the token from localStorage
        const response = await fetch(`${API_URL}/api/memoryhaven`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        if (!response.ok) throw new Error("Failed to fetch capsules.");

        const data = await response.json();
        setCapsules(data);
      } catch (error) {
        console.error("Error fetching capsules:", error);
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };

    fetchCapsules();
  }, []);

  return (
    <div className="min-h-screen bg-gray-100 py-10 px-6">
      {/* Hero Section */}
      <div className="text-center mb-10">
        <h1 className="text-4xl font-bold text-blue-600">Memory Haven</h1>
        <p className="text-lg text-gray-600 mt-2">
          Save your memories today and relive them in the future!
        </p>
      </div>

      {/* Website Info Section */}
      <div className="max-w-3xl mx-auto bg-white p-6 rounded-lg shadow-md mb-10">
        <h2 className="text-2xl font-semibold text-gray-800">About Memory Haven</h2>
        <p className="text-gray-600 mt-2">
          Memory Haven allows you to store memories, messages, and media capsules 
          that unlock at a future date. Whether it's a heartfelt letter, a surprise video, 
          or a personal time capsule, we ensure your moments are preserved securely.
        </p>
      </div>

      {/* Recent Capsules Section */}
      <h2 className="text-3xl font-semibold text-gray-800 mb-6">Recent Capsules</h2>

      {loading ? (
        <p className="text-center text-gray-600">Loading capsules...</p>
      ) : error ? (
        <p className="text-center text-red-500">Error: {error}</p>
      ) : capsules.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {capsules.map((capsule) => (
            <div
              key={capsule._id}
              className="bg-white p-4 rounded-lg shadow-md hover:shadow-lg transition duration-300"
            >
              <h3 className="text-xl font-semibold text-gray-800">{capsule.title}</h3>
              <p className="text-gray-600 mt-2">{capsule.description}</p>
              <p className="text-sm text-gray-500 mt-2">
                Unlocks on: <span className="font-medium">{new Date(capsule.unlockDate).toDateString()}</span>
              </p>
            </div>
          ))}
        </div>
      ) : (
        <p className="text-center text-gray-600">No capsules found. Create one now!</p>
      )}
    </div>
  );
}

export default Home;
